kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
// Create admin user
db = db.getSiblingDB("admin");
try {
  db.createUser({
    user: "admin",
    pwd: "admin123password",
    roles: ["root"]
  });
  print("Created admin user");
} catch(e) { print("admin user: " + e.message); }

// Create app-user with readWrite on appdb
try {
  db.getSiblingDB("appdb").createUser({
    user: "app-user",
    pwd: "app123password",
    roles: [{ role: "readWrite", db: "appdb" }]
  });
  print("Created app-user");
} catch(e) { print("app-user: " + e.message); }

// Create reportingRole custom role on appdb
try {
  db.getSiblingDB("appdb").createRole({
    role: "reportingRole",
    privileges: [{
      resource: { db: "appdb", collection: "reports" },
      actions: ["find", "aggregate"]
    }],
    roles: []
  });
  print("Created reportingRole");
} catch(e) { print("reportingRole: " + e.message); }

// Create readonly-user with read on appdb + reportingRole
try {
  db.getSiblingDB("appdb").createUser({
    user: "readonly-user",
    pwd: "readonly123password",
    roles: [
      { role: "read", db: "appdb" },
      { role: "reportingRole", db: "appdb" }
    ]
  });
  print("Created readonly-user");
} catch(e) { print("readonly-user: " + e.message); }

// Verify
print("\n=== Users ===");
db.getSiblingDB("admin").system.users.find({},{user:1,roles:1,db:1}).forEach(u => print(JSON.stringify({user:u.user, db:u.db, roles:u.roles})));
print("\n=== Roles ===");
db.getSiblingDB("appdb").getRoles({showPrivileges:true}).forEach(r => print(JSON.stringify({role:r.role, db:r.db, privileges:r.privileges})));
' 2>&1

