kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
db = db.getSiblingDB("admin");

// Drop the erroneously created app-user in appdb auth db
try {
  db.getSiblingDB("appdb").dropUser("app-user");
  print("Dropped duplicate app-user from appdb auth db");
} catch(e) { print("drop appdb app-user: " + e.message); }

// Drop the erroneously created admin user (pre-existing admin-user is sufficient)
try {
  db.dropUser("admin");
  print("Dropped extra admin user");
} catch(e) { print("drop admin: " + e.message); }

// Update app-user (auth db: admin) to have readWrite on appdb instead of read
try {
  db.updateUser("app-user", {
    roles: [{ role: "readWrite", db: "appdb" }]
  });
  print("Updated app-user: readWrite on appdb");
} catch(e) { print("updateUser app-user: " + e.message); }

// Create reportingRole in appdb
// "find" action on appdb.reports enables aggregate
try {
  db.getSiblingDB("appdb").createRole({
    role: "reportingRole",
    privileges: [{
      resource: { db: "appdb", collection: "reports" },
      actions: ["find"]
    }],
    roles: []
  });
  print("Created reportingRole on appdb");
} catch(e) { print("createRole reportingRole: " + e.message); }

// Update readonly-user (auth db: admin) to add reportingRole; keep read on appdb
try {
  db.updateUser("readonly-user", {
    roles: [
      { role: "read", db: "appdb" },
      { role: "reportingRole", db: "appdb" }
    ]
  });
  print("Updated readonly-user: read + reportingRole on appdb");
} catch(e) { print("updateUser readonly-user: " + e.message); }

// Final verification
print("\n=== Final user state ===");
db.system.users.find({},{user:1,db:1,roles:1}).forEach(u => print(JSON.stringify({user:u.user, authDB:u.db, roles:u.roles})));
print("\n=== reportingRole privileges ===");
db.getSiblingDB("appdb").getRole("reportingRole", {showPrivileges:true});
' 2>&1

